// ── Pull incoming data from CRM ─────────────────────────────
const body = $input.first().json.body || $input.first().json;
const platform    = body.platform    || 'whatsapp';
const senderName  = body.senderName  || 'ভাই/আপু';
const msgText     = body.messageText || 'New inquiry';
const convId      = body.conversationId;

// ── WhatsApp contact number (update this!) ───────────────────
const WHATSAPP_NUMBER = '+8801983333566';

// ── Gemini prompt ────────────────────────────────────────────
const prompt = `You are an AI assistant for EduExpress International, 
a study abroad consultancy in Dhaka, Bangladesh (Dhanmondi). 
We help students study in China, South Korea, UK, Hungary and more.

A new inquiry arrived via ${platform}. 
Write a warm, professional welcome message PRIMARILY IN BANGLA 
(use English only for program names, country names, and key terms).

Sender name: ${senderName}
Their message: "${msgText}"

Your message MUST include ALL of the following:
1. Warm Bangla greeting with their name
2. Welcome to EduExpress International
3. Exciting news line (copy exactly): "🎓 September Intake খোলা আছে! Diploma, Bachelor এবং Language Program-এ সীমিত আসন বাকি আছে। দ্রুত যোগাযোগ করুন!"
4. Ask which country or program they are interested in
5. Contact line: "সরাসরি WhatsApp করুন: ${WHATSAPP_NUMBER}"
6. Keep under 150 words total, use 2-3 emojis, friendly & professional tone

Return ONLY the message text — no extra commentary or labels.`;

return [{ json: {
  conversationId: convId,
  platform,
  senderName,
  geminiBodyStr: JSON.stringify({
    contents: [{ parts: [{ text: prompt }] }]
  })
}}];

// ── Extract Gemini's reply ────────────────────────────────────
const geminiResp  = $input.first().json;
const prev        = $('🧠 Build Gemini Prompt').first().json;

const aiMessage   = geminiResp?.candidates?.[0]?.content?.parts?.[0]?.text?.trim();

// Fallback if Gemini fails or returns empty
const WHATSAPP_NUMBER = '+8801983333566';
const fallback = `আস্সালামু আলাইকুম ${prev.senderName || ''}! 🎓\n\nEduExpress International-এ আপনাকে স্বাগতম!\n\n🎓 September Intake খোলা আছে! Diploma, Bachelor এবং Language Program-এ সীমিত আসন বাকি আছে। দ্রুত যোগাযোগ করুন!\n\nআপনি কোন দেশে বা কোন Program-এ পড়তে আগ্রহী? আমরা আপনাকে সঠিক guidance দিতে প্রস্তুত! 😊\n\nসরাসরি WhatsApp করুন: ${WHATSAPP_NUMBER}`;

return [{ json: {
  conversationId: prev.conversationId,
  welcomeMessage: aiMessage || fallback,
  platform: prev.platform
}}];
